import fs from 'node:fs'
import path from 'node:path'

import type * as DMMF from '@prisma/dmmf'

import { generateEnumTypes } from './generate-enums'
import { generateModelInterface, generateModelCreateInput, generateModelUpdateInput } from './generate-model-types'
import { generateModelCrudMethods } from './generate-crud-methods'
import { generateRuntimeClient } from './generate-runtime'

export type GenerateRestApiClientOptions = {
  dmmf: DMMF.Document
  outputDir: string
  baseUrl: string
}

export async function generateRestApiClient(options: GenerateRestApiClientOptions): Promise<void> {
  const { dmmf, outputDir, baseUrl } = options

  fs.mkdirSync(outputDir, { recursive: true })

  const models = dmmf.datamodel.models
  const enums = dmmf.datamodel.enums

  const chunks: string[] = []

  chunks.push(generateFileHeader())
  chunks.push(generateRuntimeClient(baseUrl))

  if (enums.length > 0) {
    chunks.push('// ============================================')
    chunks.push('// Enums')
    chunks.push('// ============================================\n')
    for (const enumType of enums) {
      chunks.push(generateEnumTypes(enumType))
    }
  }

  for (const model of models) {
    const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')

    chunks.push('// ============================================')
    chunks.push(`// ${model.name}`)
    chunks.push('// ============================================\n')
    chunks.push(generateModelInterface(model, scalarFields))
    chunks.push(generateModelCreateInput(model, scalarFields))
    chunks.push(generateModelUpdateInput(model, scalarFields))
    chunks.push(generateModelCrudMethods(model))
  }

  const output = chunks.join('\n')
  fs.writeFileSync(path.join(outputDir, 'index.ts'), output, 'utf-8')
}

function generateFileHeader(): string {
  return `// ===========================================================================
// Auto-generated by @prisma/generator-rest-api — do not edit manually.
// ===========================================================================

/* eslint-disable */
// @ts-nocheck
`
}

