/**
 * Maps Prisma scalar type names to TypeScript types used in the generated
 * REST API client interfaces.
 */
const PRISMA_SCALAR_TO_TS: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'string',
  Json: 'unknown',
  JSON: 'unknown',
  Bytes: 'string',
}

/** Return the TypeScript type string for a given Prisma scalar/enum type. */
export function mapScalarToTs(prismaType: string, kind: string): string {
  if (kind === 'enum') {
    return prismaType
  }
  return PRISMA_SCALAR_TO_TS[prismaType] ?? 'unknown'
}

