import type * as DMMF from '@prisma/dmmf'

import { mapScalarToTs } from './scalar-mapping'

function fieldToTs(field: DMMF.Field): string {
  const base = mapScalarToTs(field.type, field.kind)
  const tsType = field.isList ? `${base}[]` : base
  return tsType
}

/** Generate the main model interface containing every scalar/enum field. */
export function generateModelInterface(model: DMMF.Model, fields: readonly DMMF.Field[]): string {
  const lines = fields.map((f) => {
    const optional = f.isRequired ? '' : '?'
    const nullSuffix = f.isRequired ? '' : ' | null'
    return `  ${f.name}${optional}: ${fieldToTs(f)}${nullSuffix};`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}\n`
}

/**
 * Generate a `CreateInput` type — includes all fields except auto-generated
 * ones (`isGenerated`, `isUpdatedAt`, fields with defaults that are also ids).
 * Fields with defaults or auto-set values become optional.
 */
export function generateModelCreateInput(model: DMMF.Model, fields: readonly DMMF.Field[]): string {
  const lines = fields
    .filter((f) => !f.isGenerated && !f.isUpdatedAt)
    .map((f) => {
      const hasAutoDefault = f.hasDefaultValue || (f.isId && f.hasDefaultValue)
      const optional = !f.isRequired || hasAutoDefault ? '?' : ''
      const nullSuffix = !f.isRequired ? ' | null' : ''
      return `  ${f.name}${optional}: ${fieldToTs(f)}${nullSuffix};`
    })
  return `export interface ${model.name}CreateInput {\n${lines.join('\n')}\n}\n`
}

/** Generate an `UpdateInput` type — every field is optional. */
export function generateModelUpdateInput(model: DMMF.Model, fields: readonly DMMF.Field[]): string {
  const lines = fields
    .filter((f) => !f.isGenerated && !f.isUpdatedAt)
    .map((f) => {
      const nullSuffix = !f.isRequired ? ' | null' : ''
      return `  ${f.name}?: ${fieldToTs(f)}${nullSuffix};`
    })
  return `export interface ${model.name}UpdateInput {\n${lines.join('\n')}\n}\n`
}

