import type * as DMMF from '@prisma/dmmf'

/**
 * Generate typed CRUD functions for a single model. The functions delegate to
 * the lightweight runtime `request` helper emitted alongside the types.
 */
export function generateModelCrudMethods(model: DMMF.Model): string {
  const name = model.name
  const resource = camelCase(name)
  const idField = getIdField(model)
  const idType = idField ? mapIdType(idField) : 'string'

  return `
export async function findMany${name}(query?: Record<string, unknown>): Promise<${name}[]> {
  return request<${name}[]>('/${resource}', { method: 'GET', query });
}

export async function findUnique${name}(id: ${idType}): Promise<${name} | null> {
  return request<${name} | null>(\`/${resource}/\${id}\`, { method: 'GET' });
}

export async function create${name}(data: ${name}CreateInput): Promise<${name}> {
  return request<${name}>('/${resource}', { method: 'POST', body: data });
}

export async function update${name}(id: ${idType}, data: ${name}UpdateInput): Promise<${name}> {
  return request<${name}>(\`/${resource}/\${id}\`, { method: 'PATCH', body: data });
}

export async function delete${name}(id: ${idType}): Promise<${name}> {
  return request<${name}>(\`/${resource}/\${id}\`, { method: 'DELETE' });
}
`
}

function getIdField(model: DMMF.Model): DMMF.Field | undefined {
  const explicit = model.fields.find((f) => f.isId)
  if (explicit) return explicit

  if (model.primaryKey) {
    return model.fields.find((f) => model.primaryKey!.fields.includes(f.name))
  }
  return undefined
}

function mapIdType(field: DMMF.Field): string {
  switch (field.type) {
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    default:
      return 'string'
  }
}

function camelCase(name: string): string {
  return name.charAt(0).toLowerCase() + name.slice(1)
}

