/**
 * Emits a small fetch-based runtime that every generated CRUD function calls.
 * The runtime is self-contained so the generated output has zero runtime
 * dependencies beyond the platform `fetch` API.
 */
export function generateRuntimeClient(baseUrl: string): string {
  return `
// ============================================
// Runtime
// ============================================

const BASE_URL = '${baseUrl}';

type RequestOptions = {
  method: 'GET' | 'POST' | 'PATCH' | 'DELETE';
  body?: unknown;
  query?: Record<string, unknown>;
};

async function request<T>(path: string, options: RequestOptions): Promise<T> {
  let url = \`\${BASE_URL}\${path}\`;

  if (options.query) {
    const params = new URLSearchParams();
    for (const [key, value] of Object.entries(options.query)) {
      if (value !== undefined && value !== null) {
        params.set(key, String(value));
      }
    }
    const qs = params.toString();
    if (qs) {
      url += \`?\${qs}\`;
    }
  }

  const headers: Record<string, string> = {
    'Content-Type': 'application/json',
  };

  const response = await fetch(url, {
    method: options.method,
    headers,
    body: options.body !== undefined ? JSON.stringify(options.body) : undefined,
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(\`REST API error \${response.status}: \${text}\`);
  }

  return response.json() as Promise<T>;
}
`
}

