import fs from 'node:fs'
import os from 'node:os'
import path from 'node:path'
import { describe, test, expect, beforeEach, afterEach } from 'vitest'

import type * as DMMF from '@prisma/dmmf'

import { generateRestApiClient } from '../generate-rest-api-client'

function makeDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: { prisma: [] },
      outputObjectTypes: { model: [], prisma: [] },
      enumTypes: { prisma: [] },
      fieldRefTypes: { prisma: [] },
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  }
}

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  }
}

describe('generateRestApiClient', () => {
  let outputDir: string

  beforeEach(() => {
    outputDir = fs.mkdtempSync(path.join(os.tmpdir(), 'prisma-rest-api-test-'))
  })

  afterEach(() => {
    fs.rmSync(outputDir, { recursive: true, force: true })
  })

  test('generates an index.ts file', async () => {
    const dmmf = makeDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String', isUnique: true }),
        makeField({ name: 'name', type: 'String', isRequired: false }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(output).toContain('export interface User')
    expect(output).toContain('export interface UserCreateInput')
    expect(output).toContain('export interface UserUpdateInput')
  })

  test('generates correct interface fields', async () => {
    const dmmf = makeDmmf([
      makeModel('Post', [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'published', type: 'Boolean' }),
        makeField({ name: 'views', type: 'Int', isRequired: false }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')

    expect(output).toContain('id: number;')
    expect(output).toContain('title: string;')
    expect(output).toContain('published: boolean;')
    expect(output).toContain('views?: number | null;')
  })

  test('generates CRUD methods with correct types', async () => {
    const dmmf = makeDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String' }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'https://api.example.com' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')

    expect(output).toContain('async function findManyUser(query?: Record<string, unknown>): Promise<User[]>')
    expect(output).toContain('async function findUniqueUser(id: string): Promise<User | null>')
    expect(output).toContain('async function createUser(data: UserCreateInput): Promise<User>')
    expect(output).toContain('async function updateUser(id: string, data: UserUpdateInput): Promise<User>')
    expect(output).toContain('async function deleteUser(id: string): Promise<User>')
  })

  test('uses number type for Int id fields', async () => {
    const dmmf = makeDmmf([
      makeModel('Post', [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(output).toContain('findUniquePost(id: number)')
    expect(output).toContain('deletePost(id: number)')
  })

  test('generates enum types', async () => {
    const dmmf = makeDmmf(
      [
        makeModel('User', [
          makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
          makeField({ name: 'role', type: 'Role', kind: 'enum' }),
        ]),
      ],
      [
        {
          name: 'Role',
          values: [
            { name: 'ADMIN', dbName: null },
            { name: 'USER', dbName: null },
          ],
        },
      ],
    )

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')

    expect(output).toContain("ADMIN = 'ADMIN'")
    expect(output).toContain("USER = 'USER'")
    expect(output).toContain('role: Role;')
  })

  test('handles multiple models', async () => {
    const dmmf = makeDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String' }),
      ]),
      makeModel('Post', [
        makeField({ name: 'id', type: 'Int', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'authorId', type: 'String' }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')

    expect(output).toContain('export interface User')
    expect(output).toContain('export interface Post')
    expect(output).toContain('findManyUser')
    expect(output).toContain('findManyPost')
    expect(output).toContain("'/user'")
    expect(output).toContain("'/post'")
  })

  test('embeds the configured base URL in runtime', async () => {
    const dmmf = makeDmmf([
      makeModel('Item', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'https://custom.api/v2' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(output).toContain("const BASE_URL = 'https://custom.api/v2'")
  })

  test('makes auto-default id fields optional in CreateInput', async () => {
    const dmmf = makeDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String' }),
        makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')

    const createInput = output.slice(
      output.indexOf('export interface UserCreateInput'),
      output.indexOf('}', output.indexOf('export interface UserCreateInput')) + 1,
    )

    expect(createInput).toContain('id?: string;')
    expect(createInput).toContain('email: string;')
    expect(createInput).toContain('createdAt?: string;')
  })

  test('skips relation fields in interfaces', async () => {
    const dmmf = makeDmmf([
      makeModel('User', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'email', type: 'String' }),
        {
          kind: 'object',
          name: 'posts',
          type: 'Post',
          isRequired: false,
          isList: true,
          isUnique: false,
          isId: false,
          isReadOnly: false,
          hasDefaultValue: false,
          relationName: 'UserPosts',
          relationFromFields: [],
          relationToFields: [],
        },
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(output).not.toContain('posts')
  })

  test('handles list scalar fields', async () => {
    const dmmf = makeDmmf([
      makeModel('Tag', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'labels', type: 'String', isList: true }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')
    expect(output).toContain('labels: string[];')
  })

  test('excludes isUpdatedAt fields from create/update inputs', async () => {
    const dmmf = makeDmmf([
      makeModel('Post', [
        makeField({ name: 'id', type: 'String', isId: true, hasDefaultValue: true }),
        makeField({ name: 'title', type: 'String' }),
        makeField({ name: 'updatedAt', type: 'DateTime', isUpdatedAt: true }),
      ]),
    ])

    await generateRestApiClient({ dmmf, outputDir, baseUrl: 'http://localhost:3000/api' })

    const output = fs.readFileSync(path.join(outputDir, 'index.ts'), 'utf-8')

    const createInput = output.slice(
      output.indexOf('export interface PostCreateInput'),
      output.indexOf('}', output.indexOf('export interface PostCreateInput')) + 1,
    )
    expect(createInput).not.toContain('updatedAt')

    const updateInput = output.slice(
      output.indexOf('export interface PostUpdateInput'),
      output.indexOf('}', output.indexOf('export interface PostUpdateInput')) + 1,
    )
    expect(updateInput).not.toContain('updatedAt')
  })
})

